import 'package:flutter/material.dart';

class SpeciesInfo {
  final String nepaliName;
  final String englishName;
  final String scientificName;
  final String habitat;
  final String conservationStatus;
  final String description;
  final String funFact;

  const SpeciesInfo({
    required this.nepaliName,
    required this.englishName,
    required this.scientificName,
    required this.habitat,
    required this.conservationStatus,
    required this.description,
    required this.funFact,
  });
}

const Map<String, Color> statusColors = {
  'Critically Endangered': Color(0xFFB71C1C),
  'Endangered':            Color(0xFFE53935),
  'Vulnerable':            Color(0xFFFF6F00),
  'Near Threatened':       Color(0xFFF9A825),
  'Least Concern':         Color(0xFF388E3C),
};

String normalizeStatus(String s) {
  if (s.contains('Critically')) return 'Critically Endangered';
  if (s.contains('Endangered')) return 'Endangered';
  if (s.contains('Vulnerable')) return 'Vulnerable';
  if (s.contains('Near Threatened') || s.contains('NT')) return 'Near Threatened';
  if (s.contains('Regionally')) return 'Near Threatened';
  return 'Least Concern';
}

Map<String, List<SpeciesInfo>> get allSpecies => {
  'Mammal':    mammals,
  'Bird':      birds,
  'Fish':      fish,
  'Reptile':   reptiles,
  'Amphibian': amphibians,
  'Plant':     plants,
  'Butterfly': butterflies,
};

